mapper.select:
SELECT p.id AS plant_id, p.name AS name, p.address AS address, COALESCE(pi.capacity_sum, 0) AS capacity_sum, COALESCE(pi.total_value, 0) AS total_value, COALESCE(pi.accum_total, 0) AS accum_total, COALESCE(pi.efficiency, 0) AS efficiency, COALESCE(pi.status_code, 0) AS status_code, pi.updated_at AS updated_at FROM plant p LEFT JOIN plant_info pi ON pi.plant_id = p.id WHERE p.member_id = #{memberId}
AND p.address = #{region}
ORDER BY p.created_at DESC, p.id DESC

SELECT DATE_FORMAT(gl.base_time, '%H:00') AS hour_label, COALESCE(SUM(gl.value_actual), 0) AS total_generation FROM generation_log gl INNER JOIN inverter i ON gl.inverter_id = i.id INNER JOIN plant p ON i.plant_id = p.id WHERE p.member_id = #{memberId} AND DATE(gl.base_time) = CURDATE()
AND p.address = #{region}
GROUP BY DATE_FORMAT(gl.base_time, '%H:00') ORDER BY hour_label ASC
